import {
  LngLatBounds,
  type ViewState,
  type ViewStateChangeEvent,
} from '@vis.gl/react-maplibre';

import {
  MAX_BOUNDS_PRECISION,
  MAX_LATITUDE,
  MAX_LONGITUDE,
  MIN_LATITUDE,
  MIN_LONGITUDE,
  VIEW_STATE_PRECISION,
} from '../../../constants.js';
import type { ViewStateRequired } from '../../../types/map-view.js';
import type { ZoomState } from '../../../types/state.js';

function compareViewStates(
  currentViewState: ViewState,
  initialViewState: ViewStateRequired,
): boolean {
  return (
    currentViewState.zoom.toFixed(VIEW_STATE_PRECISION) ===
      initialViewState.zoom.toFixed(VIEW_STATE_PRECISION) &&
    currentViewState.latitude.toFixed(VIEW_STATE_PRECISION) ===
      initialViewState.latitude.toFixed(VIEW_STATE_PRECISION) &&
    currentViewState.longitude.toFixed(VIEW_STATE_PRECISION) ===
      initialViewState.longitude.toFixed(VIEW_STATE_PRECISION)
  );
}

function isMinZoomReached(currentBounds: LngLatBounds): boolean {
  return (
    (currentBounds._ne.lat.toFixed(MAX_BOUNDS_PRECISION) ===
      MAX_LATITUDE.toFixed(MAX_BOUNDS_PRECISION) &&
      currentBounds._sw.lat.toFixed(MAX_BOUNDS_PRECISION) ===
        MIN_LATITUDE.toFixed(MAX_BOUNDS_PRECISION)) ||
    (currentBounds._ne.lng.toFixed(MAX_BOUNDS_PRECISION) ===
      MAX_LONGITUDE.toFixed(MAX_BOUNDS_PRECISION) &&
      currentBounds._sw.lng.toFixed(MAX_BOUNDS_PRECISION) ===
        MIN_LONGITUDE.toFixed(MAX_BOUNDS_PRECISION))
  );
}

export function generateNewZoomState(
  event: ViewStateChangeEvent,
  initialViewState: ViewStateRequired,
  zoomToFitInProgress?: boolean,
): Partial<ZoomState> {
  const map = event.target;
  const viewState = event.viewState;
  const currentBBox = map?.getBounds();
  const zoomState: Partial<ZoomState> = {};

  if (event.type === 'zoomend') {
    zoomState.zoomInEnabled = map?.getMaxZoom() !== map?.getZoom();
    zoomState.zoomOutEnabled = !isMinZoomReached(currentBBox);
  }

  if (zoomToFitInProgress) {
    zoomState.zoomToFitEnabled = false;
    zoomState.zoomToFitInProgress = false;
  } else {
    zoomState.zoomToFitEnabled = true;
  }

  zoomState.resetEnabled = !compareViewStates(viewState, initialViewState);

  return zoomState;
}
